(window.webpackJsonp=window.webpackJsonp||[]).push([[169],{796:function(r,n){r.exports="\x3c!-- \r\ntitle: 06-Python调试\r\nsort: \r\n--\x3e \r\n# Python调试\r\n\r\n## 错误处理\r\n\r\n- 发生错误时返回错误代码。\r\n\r\n- 使用`try...except...finally...`处理错误：\r\n\r\n  > Python的错误其实也是class，所有的错误类型都继承自`BaseException`\r\n\r\n  ```python\r\n  try:\r\n      print('try...')\r\n      r = 10 / 0\r\n      print('result:', r)\r\n  except ZeroDivisionError as e:\t\t# 发生错误执行\r\n      print('except:', e)\t\t\t\t# ‘0’错误\r\n  except ValueError as e:\t\t\t\t# 值错误\r\n      print('ValueError:', e)\r\n  else:\t\t\t\t\t\t\t\t# 无错误执行\r\n      print('no error!')\r\n  finally:\t\t4\t\t\t\t\t# 一定执行\r\n      print('finally...')\r\n  print('END')\r\n  ```\r\n\r\n- 调用函数链：\r\n\r\n  > ```python\r\n  > Traceback (most recent call last):\t\t# 错误信息\r\n  >   File \"err.py\", line 11, in <module>\t# 出错位置\r\n  >     main()\r\n  >   File \"err.py\", line 9, in main\t\t# 原因再第九行\r\n  >     bar('0')\r\n  >   File \"err.py\", line 6, in bar\t\t\t# 原因在第六行\r\n  >     return foo(s) * 2\r\n  >   File \"err.py\", line 3, in foo\t\t\t# 最终原因\r\n  >     return 10 / int(s)\r\n  > ZeroDivisionError: division by zero \t# 错误类型\r\n  > ```\r\n\r\n- **记录错误**\r\n\r\n  > 可以使用内置的`logging`模块记录错误信息。\r\n  >\r\n  > 打印完错误信息后会继续执行。\r\n\r\n  ```python\r\n  # err_logging.py\r\n  \r\n  import logging\r\n  \r\n  def foo(s):\r\n      return 10 / int(s)\r\n  \r\n  def bar(s):\r\n      return foo(s) * 2\r\n  \r\n  def main():\r\n      try:\r\n          bar('0')\r\n      except Exception as e:\r\n          logging.exception(e)\r\n  \r\n  main()\r\n  print('END')\r\n  \r\n  '''\r\n  ERROR:root:division by zero\r\n  Traceback (most recent call last):\r\n    File \"err_logging.py\", line 13, in main\r\n      bar('0')\r\n    File \"err_logging.py\", line 9, in bar\r\n      return foo(s) * 2\r\n    File \"err_logging.py\", line 6, in foo\r\n      return 10 / int(s)\r\n  ZeroDivisionError: division by zero\r\n  END\r\n  '''\r\n  ```\r\n\r\n- **抛出错误**\r\n\r\n  > 可以自定义错误class，列出可能出现的错误\r\n  >\r\n  > `raise`自动抛出异常\r\n>\r\n  > 使用`raise`抛出错误实例。\r\n\r\n  ```python\r\n  class FooError(ValueError):\r\n      pass\r\n  \r\n  def foo(s):\r\n      n = int(s)\r\n      if n==0:\r\n          raise FooError('invalid value: %s' % s)\r\n      return 10 / n\r\n  \r\n  foo('0')\r\n  \r\n  '''\r\n  Traceback (most recent call last):\r\n    File \"err_throw.py\", line 11, in <module>\r\n      foo('0')\r\n    File \"err_throw.py\", line 8, in foo\r\n      raise FooError('invalid value: %s' % s)\r\n  __main__.FooError: invalid value: 0\r\n  '''\r\n  ```\r\n\r\n## 调试\r\n\r\n- 出现问题时可以用`print()`\r\n\r\n- #### **assert**\r\n\r\n  > 可以用`assert`(断言)来替代。\r\n  >\r\n  > `assert`会抛出`assertionError`异常。\r\n  >\r\n  > 启动程序时可使用`-0`参数关闭。\r\n\r\n  ```python\r\n  def foo(s):\r\n      n = int(s)\r\n      assert n != 0, 'n is zero!'\t\t\t# 表达式错误，抛出异常\r\n      return 10 / n\r\n  \r\n  def main():\r\n      foo('0')\r\n      \r\n  # python -0 err.py\r\n  ```\r\n  \r\n- ### **logging**\r\n\r\n  > `logging`不会抛出错误，而且可以输出到文件。\r\n  >\r\n  > 允许指定记录信息的级别，有`debug`，`info`，`warning`，`error`等几个级别。\r\n  >\r\n  > 当我们指定`level=INFO`时，`logging.debug`就不起作用了。指定`level=WARNING`后，`debug`和`info`就不起作用了。这样一来，你可以放心地输出不同级别的信息，也不用删除，最后统一控制输出哪个级别的信息。\r\n\r\n  ```python\r\n  import logging\r\n  logging.basicConfig(level=logging.INFO)\r\n  \r\n  s = '0'\r\n  n = int(s)\r\n  logging.info('n = %d' % n)\r\n  print(10 / n)\r\n  ```\r\n\r\n- ### **pdb**\r\n\r\n  > 让程序以单步方式运行。\r\n  \r\n  ```python\r\n  $ python -m pdb err.py\t\t# 运行代码\r\n  (Pdb) l\t\t\t\t\t\t# 显示全部代码\r\n  (Pdb) n\t\t\t\t\t\t# 运行下一行\r\n  (Pdb) p name\t\t\t\t# 可以输入命令p 变量名来查看变量\r\n  (Pdb) q\t\t\t\t\t\t# 结束程序\r\n  ```\r\n  \r\n- ### pdb.set_trace()\r\n\r\n  > 命令用法同上\r\n\r\n  ```python\r\n  import pdb\r\n  \r\n  s = '0'\r\n  n = int(s)\r\n  pdb.set_trace() \t\t\t# 设置一个断点，运行到这里会自动暂停\r\n  print(10 / n)\r\n  ```\r\n\r\n## PySnooper\r\n\r\n- @pysnooper.snoop()\r\n\r\n## 单元测试\r\n\r\n- 单元测试是用来对一个模块、一个函数或者一个类来进行正确性检验的测试工作。\r\n\r\n  > 1. 输入正数，比如`1`、`1.2`、`0.99`，期待返回值与输入相同；\r\n  > 2. 输入负数，比如`-1`、`-1.2`、`-0.99`，期待返回值与输入相反；\r\n  > 3. 输入`0`，期待返回`0`；\r\n  > 4. 输入非数值类型，比如`None`、`[]`、`{}`，期待抛出`TypeError`。\r\n\r\n- 把上面的测试用例放到一个测试模块里，就是一个完整的单元测试。\r\n\r\n  ```python\r\n  # mydict.py\r\n  class Dict(dict):\r\n  \r\n      def __init__(self, **kw):\r\n          super().__init__(**kw)\r\n  \r\n      def __getattr__(self, key):\r\n          try:\r\n              return self[key]\r\n          except KeyError:\r\n              raise AttributeError(r\"'Dict' object has no attribute '%s'\" % key)\r\n  \r\n      def __setattr__(self, key, value):\r\n          self[key] = value\r\n          \r\n  >>> d = Dict(a=1, b=2)\r\n  >>> d['a']\r\n  1\r\n  >>> d.a\r\n  1\r\n  ```\r\n\r\n  > 编写单元测试时，我们需要编写一个测试类，从`unittest.TestCase`继承。\r\n  >\r\n  > 以`test`开头的方法就是测试方法，不以`test`开头的方法不被认为是测试方法，测试的时候不会被执行。\r\n  >\r\n  > 对每一类测试都需要编写一个`test_xxx()`方法。由于`unittest.TestCase`提供了很多内置的条件判断，我们只需要调用这些方法就可以断言输出是否是我们所期望的。最常用的断言就是`assertEqual()`：\r\n\r\n  ```python\r\n  # 用于测试Dict\r\n  import unittest\r\n  \r\n  from mydict import Dict\r\n  \r\n  class TestDict(unittest.TestCase):\t\t# 继承\r\n  \r\n      def test_init(self):\r\n          d = Dict(a=1, b='test')\r\n          self.assertEqual(d.a, 1)\t\t# 判断测试是否成功\r\n          self.assertEqual(d.b, 'test')\r\n          self.assertTrue(isinstance(d, dict))\r\n  \r\n      def test_key(self):\r\n          d = Dict()\r\n          d['key'] = 'value'\r\n          self.assertEqual(d.key, 'value')\r\n  \r\n      def test_attr(self):\r\n          d = Dict()\r\n          d.key = 'value'\r\n          self.assertTrue('key' in d)\r\n          self.assertEqual(d['key'], 'value')\r\n  \r\n      def test_keyerror(self):\r\n          d = Dict()\r\n          with self.assertRaises(KeyError):\t# 判断程序会抛出KeyError\r\n              value = d['empty']\r\n  \r\n      def test_attrerror(self):\r\n          d = Dict()\r\n          with self.assertRaises(AttributeError):\r\n              value = d.empty\r\n  ```\r\n\r\n- ### setUp与tearDown\r\n\r\n  > 在测是开始及结束时执行命令\r\n\r\n### 文档测试\r\n\r\n- Python内置的“文档测试”（doctest）模块可以直接提取注释中的代码并执行测试。\r\n\r\n  ```python\r\n  # mydict2.py\r\n  class Dict(dict):\r\n      '''\r\n      Simple dict but also support access as x.y style.\r\n  \r\n      >>> d1 = Dict()\r\n      >>> d1['x'] = 100\r\n      >>> d1.x\r\n      100\r\n      >>> d1.y = 200\r\n      >>> d1['y']\r\n      200\r\n      >>> d2 = Dict(a=1, b=2, c='3')\r\n      >>> d2.c\r\n      '3'\r\n      >>> d2['empty']\r\n      Traceback (most recent call last):\r\n          ...\r\n      KeyError: 'empty'\r\n      >>> d2.empty\r\n      Traceback (most recent call last):\r\n          ...\r\n      AttributeError: 'Dict' object has no attribute 'empty'\r\n      '''\r\n      def __init__(self, **kw):\r\n          super(Dict, self).__init__(**kw)\r\n  \r\n      def __getattr__(self, key):\r\n          try:\r\n              return self[key]\r\n          except KeyError:\r\n              raise AttributeError(r\"'Dict' object has no attribute '%s'\" % key)\r\n  \r\n      def __setattr__(self, key, value):\r\n          self[key] = value\r\n  \r\n  if __name__=='__main__':\r\n      import doctest\r\n      doctest.testmod()\r\n  ```\r\n\r\n  "}}]);